CREATE TABLE discount_codes (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code TEXT UNIQUE NOT NULL, type TEXT NOT NULL CHECK (type IN ('flat', 'percentage')), value NUMERIC NOT NULL, expiry_date TIMESTAMP WITH TIME ZONE, usage_limit INT, times_used INT DEFAULT 0, active BOOLEAN DEFAULT true, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()); ALTER TABLE bookings ADD COLUMN discount_code_id UUID REFERENCES discount_codes(id); ALTER TABLE bookings ADD COLUMN discount_cents INT DEFAULT 0; ALTER TABLE discount_codes ENABLE ROW LEVEL SECURITY; CREATE POLICY "Admins can manage discount codes" ON discount_codes FOR ALL USING (EXISTS (SELECT 1 FROM admin_users WHERE email = auth.jwt()->>'email')); CREATE POLICY "Anyone can read active discount codes" ON discount_codes FOR SELECT USING (active = true);